onClick:
{{
(() => {

	if (!inpClaveAnulacion.text.trim()) {

		showAlert(
			"Ingrese la clave de autorización",
			"warning"
		);

		return;
	}

	if (!txtRazonAnulacion.text.trim()) {

		showAlert(
			"Ingrese la razón",
			"warning"
		);

		return;
	}

	const queryEjecutar =
		appsmith.store.accionOC === "CERRAR"
			? CerrarOC
			: AnularOC;

	const mensajeExito =
		appsmith.store.accionOC === "CERRAR"
			? "Orden cerrada correctamente"
			: "Orden anulada correctamente";

	queryEjecutar.run()
		.then(async () => {

			showAlert(
				mensajeExito,
				"success"
			);

			closeModal("mdlAnularOC");

			await resetWidget(
				"inpClaveAnulacion"
			);

			await resetWidget(
				"txtRazonAnulacion"
			);

			await BuscarOC.run();

			await ObtenerOC.run();

		})
		.catch((error) => {

			showAlert(
				error.message,
				"error"
			);

		});

})()
}}
